# BEST PRACTICE: Hybrid Reservoir Pattern with validation gates
import hashlib
from collections import deque
from datetime import datetime

class CricketDataPipeline:
    def __init__(self, reservoir_size=100000, batch_window_days=7):
        self.batting_records = deque(maxlen=reservoir_size)  # Recent high-quality samples
        self.bowling_metrics = {}  # Versioned metadata
        self.batch_window_days = batch_window_days
        self.validation_checksum = None

    def ingest_match_data(self, match_sample):
        """Best practice: validate before adding to reservoir"""
        # Check for quality gates
        if self._validate_sample_quality(match_sample):
            self.batting_records.append(match_sample)
            return True
        return False

    def _validate_sample_quality(self, sample):
        """Catch corrupted or biased data early"""
        required_fields = ['player_name', 'runs', 'wicket_type', 'timestamp']
        if not all(field in sample for field in required_fields):
            return False
        if sample['runs'] < 0 or sample['runs'] > 300:
            return False  # Sanity check
        return True

    def create_training_batch(self, sample_date):
        """Best practice: deterministic sampling with version tracking"""
        filtered = [s for s in self.batting_records 
                   if self._is_within_window(s['timestamp'], sample_date)]
        batch_hash = hashlib.sha256(
            str([(s['player_name'], s['runs']) for s in filtered]).encode()
        ).hexdigest()[:8]
        return {
            'samples': filtered,
            'batch_version': batch_hash,
            'created_at': datetime.now().isoformat(),
            'sample_count': len(filtered)
        }

    def _is_within_window(self, timestamp, reference_date):
        return abs((datetime.fromisoformat(timestamp) - 
                   datetime.fromisoformat(reference_date)).days) <= self.batch_window_days

# ANTI-PATTERN: No validation, unbounded memory, non-deterministic sampling
class PoorCricketPipeline:
    def __init__(self):
        self.all_matches = []  # Grows infinitely—memory leak!

    def add_data(self, match):
        """Anti-pattern: no quality checks"""
        self.all_matches.append(match)  # Could be corrupted, duplicate, or biased

    def get_batch(self):
        """Anti-pattern: random sampling, non-reproducible"""
        import random
        return random.sample(self.all_matches, 1000)  # Different results every run!
